New algorithm: For each order, evaluate cost increase of insertion into every existing route and a new route, then select the assignment with the smallest increase; fallback to first feasible if none found.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj

		bestIdx := -1
		bestCostInc := 1e18
		useNewAssign := false

		// evaluate insertion into existing routes
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			oldCost := dispatch.Assigns[ii].Cost
			if dispatch.Assigns[ii].StationsLen == 0 {
				oldCost = 0
			}
			if !dispatch.Assigns[ii].AddShip(shipID, ori, des) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				inc := newCost - oldCost
				if inc < bestCostInc {
					bestCostInc = inc
					bestIdx = ii
					useNewAssign = false
				}
			}
			// rollback
			dispatch.Assigns[ii].RemoveShip(shipID)
			dispatch.Assigns[ii].GenRoute()
		}

		// evaluate insertion into a new empty route
		if dispatch.AssignsLen < MAXASSIGNS {
			ii := dispatch.AssignsLen
			if dispatch.Assigns[ii].AddShip(shipID, ori, des) {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost >= 0 {
					inc := newCost // old cost is effectively 0
					if inc < bestCostInc {
						bestCostInc = inc
						bestIdx = ii
						useNewAssign = true
					}
				}
				// rollback
				dispatch.Assigns[ii].RemoveShip(shipID)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		// apply the best insertion found
		if bestIdx >= 0 {
			if useNewAssign {
				dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[bestIdx].GenRoute()
				dispatch.AssignsLen++
			} else {
				dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[bestIdx].GenRoute()
			}
		} else {
			// fallback: safe seed-style first-feasible insertion
			inserted := false
			for ii := 0; ii <= dispatch.AssignsLen && ii < MAXASSIGNS; ii++ {
				if ii == dispatch.AssignsLen {
					if dispatch.AssignsLen >= MAXASSIGNS {
						break
					}
					if dispatch.Assigns[ii].AddShip(shipID, ori, des) {
						dispatch.Assigns[ii].GenRoute()
						if dispatch.Assigns[ii].Cost >= 0 {
							dispatch.AssignsLen++
							inserted = true
							break
						}
						dispatch.Assigns[ii].RemoveShip(shipID)
						dispatch.Assigns[ii].GenRoute()
					}
				} else {
					if !dispatch.Assigns[ii].AddShip(shipID, ori, des) {
						continue
					}
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						inserted = true
						break
					}
					dispatch.Assigns[ii].RemoveShip(shipID)
					dispatch.Assigns[ii].GenRoute()
				}
			}
			// if still not inserted, order cannot be placed; do not break loop
			_ = inserted
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

